import anthropic

client = anthropic.Anthropic()

def run_agent(user_message: str, tools: list) -> str:
    messages = [{"role": "user", "content": user_message}]

    while True:
        response = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=2048,
            tools=tools,
            messages=messages,
        )

        # Append assistant response to history
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            # Extract final text
            return next(b.text for b in response.content if hasattr(b, "text"))

        if response.stop_reason == "tool_use":
            tool_results = []
            for block in response.content:
                if block.type != "tool_use":
                    continue
                # Execute the tool
                result = dispatch_tool(block.name, block.input)
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": result,
                })
            # Feed results back — this is the key step in sequential calls
            messages.append({"role": "user", "content": tool_results})

import json

def get_weather(city: str) -> str:
    # Real implementation would call a weather API
    return json.dumps({"city": city, "temp_c": 22, "condition": "clear"})

def plan_activity(condition: str) -> str:
    mapping = {
        "clear": ["hiking", "cycling", "outdoor yoga"],
        "cloudy": ["museum visit", "shopping", "coffee shop"],
        "rainy": ["indoor climbing", "cinema", "cooking class"],
    }
    activities = mapping.get(condition, ["walking"])
    return json.dumps({"activities": activities})

def book_reservation(activity: str) -> str:
    confirmation_id = f"R{hash(activity) % 9000 + 1000}"
    return json.dumps({"confirmed": True, "activity": activity, "id": confirmation_id})

TOOL_REGISTRY = {
    "get_weather": lambda inp: get_weather(**inp),
    "plan_activity": lambda inp: plan_activity(**inp),
    "book_reservation": lambda inp: book_reservation(**inp),
}

def dispatch_tool(name: str, tool_input: dict) -> str:
    handler = TOOL_REGISTRY.get(name)
    if handler is None:
        return json.dumps({"error": f"Unknown tool: {name}"})
    try:
        return handler(tool_input)
    except Exception as exc:
        return json.dumps({"error": str(exc)})

MAX_TOOL_TURNS = 10  # abort after this many sequential tool calls

def run_agent_safe(user_message: str, tools: list) -> str:
    messages = [{"role": "user", "content": user_message}]
    tool_turns = 0

    while True:
        response = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=2048,
            tools=tools,
            messages=messages,
        )
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            return next(b.text for b in response.content if hasattr(b, "text"))

        if response.stop_reason == "tool_use":
            tool_turns += 1
            if tool_turns > MAX_TOOL_TURNS:
                raise RuntimeError(
                    f"Agent exceeded {MAX_TOOL_TURNS} sequential tool turns — possible loop"
                )

            tool_results = []
            for block in response.content:
                if block.type != "tool_use":
                    continue
                result = dispatch_tool(block.name, block.input)
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": result,
                })
            messages.append({"role": "user", "content": tool_results})

import json

def print_conversation(messages: list) -> None:
    for msg in messages:
        role = msg["role"].upper()
        content = msg["content"]
        if isinstance(content, str):
            print(f"[{role}] {content[:100]}")
        elif isinstance(content, list):
            for block in content:
                if isinstance(block, dict):
                    btype = block.get("type", "?")
                    if btype == "tool_result":
                        print(f"[{role}] tool_result({block['tool_use_id'][:12]}…): {str(block['content'])[:80]}")
                else:
                    # Pydantic model from SDK
                    if block.type == "text":
                        print(f"[{role}] text: {block.text[:80]}")
                    elif block.type == "tool_use":
                        print(f"[{role}] tool_use: {block.name}({json.dumps(block.input)[:60]})")

