import json

def get_weather(city: str) -> str:
    data = {"city": city, "temp_c": 22, "condition": "clear", "humidity": 65,
            "wind_kph": 12, "uv_index": 4, "raw_forecast": "... 2000 bytes ..."}
    # Trim: only return what the next tool needs
    trimmed = {k: data[k] for k in ("city", "temp_c", "condition")}
    return json.dumps(trimmed)
    # Returns: {"city": "NYC", "temp_c": 22, "condition": "clear"}
    # Instead of the full 2 KB blob — keeps context window lean.

import json

def safe_dispatch(name: str, tool_input: dict) -> dict:
    """Return a tool_result dict — never raises."""
    try:
        content = dispatch_tool(name, tool_input)
        return {"is_error": False, "content": content}
    except Exception as exc:
        return {
            "is_error": True,
            "content": json.dumps({"error": type(exc).__name__, "message": str(exc)}),
        }

# In the agent loop:
for block in response.content:
    if block.type != "tool_use":
